import React, { useEffect } from 'react';
import { Link, useLocation } from 'react-router-dom';

const Navbar = () => {
  const location = useLocation();

  useEffect(() => {
    if (location.pathname !== '/') return; // Only run scroll logic on home page

    const links = document.querySelectorAll('.navmenu a');

    const onScroll = () => {
      let scrollPosition = window.scrollY;

      links.forEach(link => {
        const href = link.getAttribute('href');
        if (!href || !href.startsWith('#')) return; // Skip invalid links

        let section = document.querySelector(href);

        if (section) {
          let sectionTop = section.offsetTop - 100;
          let sectionBottom = sectionTop + section.offsetHeight;

          if (scrollPosition >= sectionTop && scrollPosition < sectionBottom) {
            links.forEach(nav => nav.classList.remove('active'));
            link.classList.add('active');
          }
        }
      });
    };

    window.addEventListener('scroll', onScroll);
    onScroll();

    return () => {
      window.removeEventListener('scroll', onScroll);
    };
  }, [location.pathname]);

  return (
    <header id="header" className="header d-flex flex-column justify-content-center">
      <i className="header-toggle d-xl-none bi bi-list"></i>
      <nav id="navmenu" className="navmenu">
        <ul>

          {location.pathname === "/" ? (
            <>
            <li>
            <Link to="/" className={location.pathname === "/" ? "active" : ""}>
              <i className="bi bi-house navicon"></i><span>Home</span>
            </Link>
          </li>
              <li><a href="/"><i className="bi bi-house navicon"></i><span>Home</span></a></li>
              <li><a href="#about"><i className="bi bi-person navicon"></i><span>About</span></a></li>
              <li><a href="#skills"><i className="bi bi-lightbulb navicon"></i><span>Skills</span></a></li>
              <li><a href="#resume"><i className="bi bi-file-earmark-text navicon"></i><span>Resume</span></a></li>
              <li><a href="#platforms"><i className="bi bi-hdd-stack navicon"></i><span>Platform</span></a></li>
              <li><a href="#contact"><i className="bi bi-envelope navicon"></i><span>Contact</span></a></li>
            </>
          ) : (
            <li>
              <Link to="/" className="active">
                <i className="bi bi-arrow-left navicon"></i><span>Back to Home</span>
              </Link>
            </li>
          )}
          <li>
            <Link to="/projects" className={location.pathname === "/projects" ? "active" : ""}>
              <i className="bi bi-folder navicon"></i><span>Projects</span>
            </Link>
          </li>
        </ul>
      </nav>
    </header>
  );
};

export default Navbar;
